    public static Kernel32_INPUT_RECORD[] readConsoleInputHelper(long handle, int count, boolean peek)
            throws IOException {
        int[] length = new int[1];
        int res;
        long inputRecordPtr = 0;
        try {
            inputRecordPtr = malloc(Kernel32_INPUT_RECORD.SIZEOF * count);
            if (inputRecordPtr == 0) {
                throw new IOException("cannot allocate memory with JNI");
            }
            res = peek
                    ? PeekConsoleInputW(handle, inputRecordPtr, count, length)
                    : ReadConsoleInputW(handle, inputRecordPtr, count, length);
            if (res == 0) {
                throw new IOException("ReadConsoleInputW failed: " + getLastErrorMessage());
            }
            if (length[0] <= 0) {
                return new Kernel32_INPUT_RECORD[0];
            }
            Kernel32_INPUT_RECORD[] records = new Kernel32_INPUT_RECORD[length[0]];
            for (int i = 0; i < records.length; i++) {
                records[i] = new Kernel32_INPUT_RECORD();
                Kernel32_INPUT_RECORD.memmove(
                        records[i], inputRecordPtr + i * Kernel32_INPUT_RECORD.SIZEOF, Kernel32_INPUT_RECORD.SIZEOF);
            }
            return records;
        } finally {
            if (inputRecordPtr != 0) {
                free(inputRecordPtr);
            }
        }
    }
```

